from flask import Flask, request, jsonify, g
from prometheus_client import Counter, Gauge, Histogram, generate_latest, CONTENT_TYPE_LATEST
import time
import random
import threading

app = Flask(__name__)

REQUEST_COUNT = Counter(
    "flask_http_requests_total",
    "Total HTTP requests",
    ["method", "endpoint", "http_status"]
)

REQUEST_LATENCY = Histogram(
    "flask_http_request_duration_seconds",
    "HTTP request latency in seconds",
    ["method", "endpoint"],
    buckets=(0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1.0, 2.5, 5.0, 10.0)
)

IN_PROGRESS = Gauge(
    "flask_http_requests_in_progress",
    "Number of HTTP requests in progress",
    ["method", "endpoint"]
)

ACTIVE_USERS = Gauge(
    "business_active_users",
    "Number of active users in the system"
)

ORDERS_CREATED = Counter(
    "business_orders_created_total",
    "Total number of orders created",
    ["status"]
)

ORDER_VALUE = Histogram(
    "business_order_value",
    "Distribution of order values",
    buckets=(10, 25, 50, 100, 250, 500, 1000, 2500, 5000)
)

INVENTORY_LEVEL = Gauge(
    "business_inventory_level",
    "Current inventory level",
    ["product"]
)

PAYMENT_PROCESSING_TIME = Histogram(
    "business_payment_processing_seconds",
    "Payment processing time in seconds",
    buckets=(0.01, 0.05, 0.1, 0.25, 0.5, 1.0, 2.0, 5.0)
)

FAILED_PAYMENTS = Counter(
    "business_failed_payments_total",
    "Total failed payments",
    ["reason"]
)

PRODUCTS = ["widget", "gadget", "doodad"]

for product in PRODUCTS:
    INVENTORY_LEVEL.labels(product=product).set(random.randint(50, 200))

ACTIVE_USERS.set(42)


@app.before_request
def before_request():
    endpoint = request.endpoint or request.path
    g.start_time = time.time()
    g.metric_endpoint = endpoint
    IN_PROGRESS.labels(method=request.method, endpoint=endpoint).inc()


@app.after_request
def after_request(response):
    endpoint = getattr(g, "metric_endpoint", request.endpoint or request.path)
    status = response.status_code
    REQUEST_COUNT.labels(
        method=request.method,
        endpoint=endpoint,
        http_status=str(status)
    ).inc()
    if hasattr(g, "start_time"):
        REQUEST_LATENCY.labels(
            method=request.method,
            endpoint=endpoint
        ).observe(time.time() - g.start_time)
    IN_PROGRESS.labels(method=request.method, endpoint=endpoint).dec()
    return response


@app.teardown_request
def teardown_request(exception):
    if exception is not None:
        endpoint = getattr(g, "metric_endpoint", request.endpoint or request.path)
        try:
            IN_PROGRESS.labels(method=request.method, endpoint=endpoint).dec()
        except Exception:
            pass


@app.route("/")
def index():
    return jsonify({
        "service": "flask-prometheus-app",
        "status": "ok"
    })


@app.route("/health")
def health():
    return jsonify({"healthy": True})


@app.route("/users/active", methods=["GET", "POST"])
def active_users():
    if request.method == "POST":
        data = request.get_json(silent=True) or {}
        value = data.get("count")
        if isinstance(value, int) and value >= 0:
            ACTIVE_USERS.set(value)
            return jsonify({"active_users": value}), 200
        return jsonify({"error": "count must be a non-negative integer"}), 400
    return jsonify({"active_users": int(ACTIVE_USERS._value.get())})


@app.route("/orders", methods=["POST"])
def create_order():
    data = request.get_json(silent=True) or {}
    product = data.get("product", random.choice(PRODUCTS))
    value = float(data.get("value", round(random.uniform(20, 1000), 2)))

    if product not in PRODUCTS:
        return jsonify({"error": "invalid product"}), 400

    ORDER_VALUE.observe(value)

    current_inventory = INVENTORY_LEVEL.labels(product=product)._value.get()
    if current_inventory <= 0:
        ORDERS_CREATED.labels(status="rejected_out_of_stock").inc()
        return jsonify({"status": "rejected", "reason": "out_of_stock"}), 409

    processing_time = random.uniform(0.02, 0.8)
    time.sleep(processing_time)
    PAYMENT_PROCESSING_TIME.observe(processing_time)

    if random.random() < 0.1:
        FAILED_PAYMENTS.labels(reason="payment_declined").inc()
        ORDERS_CREATED.labels(status="failed_payment").inc()
        return jsonify({"status": "failed", "reason": "payment_declined"}), 402

    INVENTORY_LEVEL.labels(product=product).dec()
    ORDERS_CREATED.labels(status="success").inc()

    return jsonify({
        "status": "created",
        "product": product,
        "value": value
    }), 201


@app.route("/inventory", methods=["GET"])
def inventory():
    data = {
        product: int(INVENTORY_LEVEL.labels(product=product)._value.get())
        for product in PRODUCTS
    }
    return jsonify(data)


@app.route("/inventory/<product>/restock", methods=["POST"])
def restock_inventory(product):
    if product not in PRODUCTS:
        return jsonify({"error": "invalid product"}), 400

    data = request.get_json(silent=True) or {}
    amount = data.get("amount", 10)

    if not isinstance(amount, int) or amount <= 0:
        return jsonify({"error": "amount must be a positive integer"}), 400

    INVENTORY_LEVEL.labels(product=product).inc(amount)
    return jsonify({
        "product": product,
        "inventory": int(INVENTORY_LEVEL.labels(product=product)._value.get())
    })


@app.route("/metrics")
def metrics():
    return generate_latest(), 200, {"Content-Type": CONTENT_TYPE_LATEST}


def background_metrics_updater():
    while True:
        ACTIVE_USERS.set(random.randint(20, 200))
        for product in PRODUCTS:
            current = INVENTORY_LEVEL.labels(product=product)._value.get()
            if current < 20:
                INVENTORY_LEVEL.labels(product=product).inc(random.randint(20, 50))
        time.sleep(15)


if __name__ == "__main__":
    thread = threading.Thread(target=background_metrics_updater, daemon=True)
    thread.start()
    app.run(host="0.0.0.0", port=5000)